     9→
    10→// Plan metadata — only non-translatable values here
    11→const PLAN_META = [
    12→  { id: 'free',     price: 0,  featureCount: 5, lockedCount: 5, hasBadge: false, highlight: false, priceId: null },
    13→  { id: 'pro',      price: 29, featureCount: 7, lockedCount: 0, hasBadge: true,  highlight: true,  priceId: process.env.REACT_APP_STRIPE_PRO_PRICE_ID },
    14→  { id: 'business', price: 79, featureCount: 7, lockedCount: 0, hasBadge: true,  highlight: false, priceId: process.env.REACT_APP_STRIPE_BUSINESS_PRICE_ID },
    15→];
    16→
    17→// Comparison row value keys (text values that need translation use a key, icons/numbers stay as-is)
    18→const COMPARISON_ROWS = [
    19→  { idx: 0,  free: '3/day',  pro: 'unlimited', business: 'unlimited' },
    20→  { idx: 1,  free: '✅',     pro: '✅',        business: '✅' },
    21→  { idx: 2,  free: '✅',     pro: '✅',        business: '✅' },
    22→  { idx: 3,  free: '❌',     pro: '✅',        business: '✅' },
    23→  { idx: 4,  free: '❌',     pro: '✅',        business: '✅' },
    24→  { idx: 5,  free: '❌',     pro: '❌',        business: '✅' },
    25→  { idx: 6,  free: '❌',     pro: '❌',        business: '✅' },
    26→  { idx: 7,  free: '❌',     pro: '❌',        business: '✅' },
    27→  { idx: 8,  free: '1',      pro: '1',         business: '10' },
