    44→export default function PricingPage() {
    45→  const { currentUser } = useAuth();
    46→  const { subscription } = useSubscription();
    47→  const navigate = useNavigate();
    48→  const { t } = useTranslation();
    49→  const [loadingPlan, setLoadingPlan] = useState(null);
    50→  const [error, setError] = useState('');
    51→
    52→  async function handlePlanSelect(plan) {
    53→    if (plan.id === 'free') {
    54→      navigate('/auth?mode=register');
    55→      return;
    56→    }
    57→
    58→    if (!currentUser) {
    59→      navigate('/auth?mode=register');
    60→      return;
    61→    }
    62→
    63→    if (!plan.priceId || plan.priceId === 'undefined') {
    64→      setError('Payment system is not configured yet. Please add Stripe price IDs to your environment variables.');
    65→      return;
    66→    }
    67→
    68→    setError('');
    69→    setLoadingPlan(plan.id);
    70→    try {
    71→      const { url } = await createCheckoutSession(plan.priceId);
    72→      window.location.href = url;
    73→    } catch (err) {
    74→      setError(err.message || 'Failed to start checkout. Please try again.');
    75→    }
    76→    setLoadingPlan(null);
    77→  }
    78→
    79→  function getPlanCta(plan) {
    80→    if (!currentUser && plan.id !== 'free') return t('pricing.signUpToStart', { defaultValue: 'Sign Up to Start' });
    81→    if (subscription === plan.id) return t('pricing.currentPlan', { defaultValue: '✅ Current Plan' });
    82→    if (plan.id === 'free' && subscription !== 'free') return t('pricing.downgrade', { defaultValue: 'Downgrade' });
    83→    return t(`pricing.plan.${plan.id}.cta`);
    84→  }
    85→
    86→  function translateVal(val) {
    87→    if (val === 'unlimited') return t('pricing.comparison.unlimited', { defaultValue: 'Unlimited' });
    88→    if (val === 'email')     return t('pricing.comparison.email',     { defaultValue: 'Email' });
    89→    if (val === 'priority')  return t('pricing.comparison.priority',  { defaultValue: 'Priority' });
    90→    if (val === 'dedicated') return t('pricing.comparison.dedicated', { defaultValue: 'Dedicated' });
    91→    if (val === 'addon')     return t('pricing.comparison.addon',     { defaultValue: '➕ Add-on' });
    92→    return val;
    93→  }
    94→
    95→  return (
    96→    <div className="page">
    97→      <div className="pricing">
    98→        {/* Hero */}
    99→        <motion.div
   100→          className="pricing__hero container"
   101→          initial={{ opacity: 0, y: 30 }}
   102→          animate={{ opacity: 1, y: 0 }}
   103→          transition={{ duration: 0.6 }}
   104→        >
   105→          <span className="badge badge-primary">
   106→            {t('pricing.hero.badge', { defaultValue: 'Simple, Transparent Pricing' })}
   107→          </span>
   108→          <h1 className="pricing__title">
   109→            {t('pricing.hero.titlePre', { defaultValue: 'Choose Your' })}{' '}
   110→            <span className="gradient-text">{t('pricing.hero.titleHighlight', { defaultValue: 'Growth Plan' })}</span>
   111→          </h1>
   112→          <p className="pricing__subtitle">
   113→            {t('pricing.hero.subtitle', { defaultValue: "Start free. Upgrade when you're ready. No contracts, cancel anytime." })}
   114→          </p>
   115→        </motion.div>
   116→
   117→        {error && (
   118→          <div className="container">
   119→            <div className="alert alert-warning" style={{ marginBottom: '2rem' }}>
   120→              ⚠️ {error}
   121→            </div>
   122→          </div>
   123→        )}
   124→
   125→        {/* Plans */}
