   127→          <motion.div
   128→            className="pricing__plans"
   129→            initial="hidden"
   130→            animate="visible"
   131→            variants={stagger}
   132→          >
   133→            {PLAN_META.map((plan) => {
   134→              const features = Array.from({ length: plan.featureCount }, (_, i) =>
   135→                t(`pricing.plan.${plan.id}.feature.${i}`)
   136→              );
   137→              const locked = Array.from({ length: plan.lockedCount }, (_, i) =>
   138→                t(`pricing.plan.${plan.id}.locked.${i}`)
   139→              );
   140→
   141→              return (
   142→                <motion.div
   143→                  key={plan.id}
   144→                  className={`pricing__plan ${plan.highlight ? 'pricing__plan--highlight' : ''} ${subscription === plan.id ? 'pricing__plan--current' : ''}`}
   145→                  variants={fadeUp}
   146→                  whileHover={{ y: plan.highlight ? -8 : -4 }}
   147→                  transition={{ type: 'spring', stiffness: 300, damping: 25 }}
   148→                >
   149→                  {plan.highlight && <div className="pricing__plan-glow" />}
   150→
   151→                  {plan.hasBadge && subscription !== plan.id && (
   152→                    <div className="pricing__plan-badge">
   153→                      {t(`pricing.plan.${plan.id}.badge`)}
   154→                    </div>
   155→                  )}
   156→
   157→                  {subscription === plan.id && (
