   181→                  >
   182→                    {loadingPlan === plan.id ? (
   183→                      <><span className="spinner" /> {t('pricing.processing', { defaultValue: 'Processing...' })}</>
   184→                    ) : (
   185→                      getPlanCta(plan)
   186→                    )}
   187→                  </button>
   188→
   189→                  <div className="pricing__features">
   190→                    {features.map((f) => (
   191→                      <div key={f} className="pricing__feature pricing__feature--included">
   192→                        <span className="pricing__feature-icon">✅</span>
   193→                        <span>{f}</span>
   194→                      </div>
   195→                    ))}
   196→                    {locked.map((f) => (
   197→                      <div key={f} className="pricing__feature pricing__feature--locked">
   198→                        <span className="pricing__feature-icon">🔒</span>
   199→                        <span>{f}</span>
   200→                      </div>
   201→                    ))}
   202→                  </div>
   203→                </motion.div>
   204→              );
   205→            })}
   206→          </motion.div>
   207→        </div>
   208→
   209→        {/* N8n Add-on */}
   210→        <div className="container">
   211→          <motion.div
   212→            className="pricing__addon"
   213→            initial={{ opacity: 0, y: 20 }}
   214→            whileInView={{ opacity: 1, y: 0 }}
   215→            viewport={{ once: true, margin: '-60px' }}
   216→            transition={{ duration: 0.5 }}
   217→          >
   218→            <div className="pricing__addon-left">
   219→              <span className="badge badge-primary pricing__addon-badge">
   220→                {t('pricing.addon.badge', { defaultValue: '⚡ Add-on' })}
   221→              </span>
   222→              <h3 className="pricing__addon-title">
   223→                {t('pricing.addon.title', { defaultValue: 'N8n Automation' })}
   224→              </h3>
   225→              <p className="pricing__addon-desc">
   226→                {t('pricing.addon.desc', { defaultValue: 'Design powerful no-code automations using n8n — available to any plan.' })}
   227→              </p>
   228→              <ul className="pricing__addon-features">
   229→                {[0, 1, 2, 3].map((i) => (
   230→                  <li key={i}>✅ {t(`pricing.addon.feature.${i}`)}</li>
   231→                ))}
   232→              </ul>
   233→            </div>
   234→
   235→            <div className="pricing__addon-right">
   236→              <div className="pricing__addon-price">
   237→                <span className="pricing__addon-amount">
   238→                  {t('pricing.addon.price', { defaultValue: '€10' })}
   239→                </span>
   240→                <span className="pricing__addon-period">
   241→                  {t('pricing.addon.period', { defaultValue: '/ 3 days' })}
   242→                </span>
   243→              </div>
   244→              <p className="pricing__addon-renew">
   245→                {t('pricing.addon.renew', { defaultValue: 'Renews every 3 days · Works with any plan' })}
   246→              </p>
   247→              <button
   248→                className="btn btn-primary pricing__plan-cta"
   249→                onClick={() => {
   250→                  if (!currentUser) navigate('/auth?mode=register');
   251→                }}
   252→              >
   253→                {t('pricing.addon.cta', { defaultValue: 'Get Add-on →' })}
   254→              </button>
   255→            </div>
   256→          </motion.div>
   257→        </div>
   258→
   259→        {/* Comparison table */}
   260→        <div className="container">
   261→          <motion.div
   262→            className="pricing__comparison"
   263→            initial={{ opacity: 0, y: 30 }}
   264→            whileInView={{ opacity: 1, y: 0 }}
   265→            viewport={{ once: true, margin: '-80px' }}
   266→            transition={{ duration: 0.6 }}
   267→          >
   268→            <h2 className="pricing__comparison-title">
   269→              {t('pricing.comparison.title', { defaultValue: 'Full Feature Comparison' })}
   270→            </h2>
   271→            <div className="pricing__table-wrap">
   272→              <table className="pricing__table">
   273→                <thead>
   274→                  <tr>
   275→                    <th>{t('pricing.comparison.featureCol', { defaultValue: 'Feature' })}</th>
   276→                    <th>{t('pricing.plan.free.name', { defaultValue: 'Free' })}</th>
   277→                    <th className="pricing__th--highlight">Pro</th>
   278→                    <th>{t('pricing.plan.business.name', { defaultValue: 'Business' })}</th>
   279→                  </tr>
   280→                </thead>
   281→                <tbody>
   282→                  {COMPARISON_ROWS.map((row) => (
   283→                    <tr key={row.idx}>
   284→                      <td>{t(`pricing.comparison.row.${row.idx}`)}</td>
   285→                      <td>{translateVal(row.free)}</td>
   286→                      <td className="pricing__td--highlight">{translateVal(row.pro)}</td>
   287→                      <td>{translateVal(row.business)}</td>
   288→                    </tr>
   289→                  ))}
   290→                </tbody>
   291→              </table>
   292→            </div>
   293→          </motion.div>
   294→        </div>
   295→
   296→        {/* FAQ */}
   297→        <div className="container pricing__faq">
   298→          <h2 className="pricing__comparison-title">
   299→            {t('pricing.faq.title', { defaultValue: 'Frequently Asked Questions' })}
   300→          </h2>
   301→          <div className="pricing__faq-grid">
   302→            {Array.from({ length: FAQ_COUNT }, (_, i) => (
   303→              <div key={i} className="pricing__faq-item">
   304→                <h4>{t(`pricing.faq.${i}.q`)}</h4>
   305→                <p>{t(`pricing.faq.${i}.a`)}</p>
   306→              </div>
   307→            ))}
   308→          </div>
   309→        </div>
   310→
   311→        {/* CTA */}
   312→        <div className="container pricing__bottom-cta">
   313→          <motion.div
   314→            className="pricing__cta-card"
   315→            initial={{ opacity: 0, y: 20 }}
   316→            whileInView={{ opacity: 1, y: 0 }}
   317→            viewport={{ once: true }}
   318→          >
   319→            <h2>
   320→              {t('pricing.cta.titlePre', { defaultValue: 'Ready to' })}{' '}
   321→              <span className="gradient-text">{t('pricing.cta.titleHighlight', { defaultValue: 'Get Started?' })}</span>
   322→            </h2>
   323→            <p>{t('pricing.cta.subtitle', { defaultValue: 'Join thousands of marketers, founders, and agencies growing with AI.' })}</p>
   324→            <Link to="/auth?mode=register" className="btn btn-primary btn-lg">
   325→              {t('pricing.cta.btn', { defaultValue: 'Start Free Today →' })}
   326→            </Link>
   327→          </motion.div>
   328→        </div>
   329→      </div>
   330→    </div>
   331→  );
   332→}
