    10→export default function CategoryPage() {
    11→  const { categoryId } = useParams();
    12→  const navigate = useNavigate();
    13→  const { isCategoryLocked } = useSubscription();
    14→  const { t } = useTranslation();
    15→
    16→  const category = getCategoryById(categoryId);
    17→  const [selectedTool, setSelectedTool] = useState(null);
    18→  const [sidebarOpen, setSidebarOpen] = useState(true);
    19→
    20→  useEffect(() => {
    21→    if (!category) {
    22→      navigate('/dashboard');
    23→      return;
    24→    }
    25→    if (category.tools.length > 0) {
    26→      setSelectedTool(category.tools[0]);
    27→    }
    28→  }, [categoryId, category, navigate]);
    29→
    30→  if (!category) return null;
    31→
    32→  const locked = isCategoryLocked(categoryId);
    33→  const catName = t(`cat.${category.id}.name`, { defaultValue: category.name });
    34→
    35→  return (
    36→    <div className="page">
    37→      <div className="category">
    38→        {/* Top breadcrumb bar */}
    39→        <div className="category__topbar">
    40→          <div className="container">
    41→            <div className="category__breadcrumb">
    42→              <Link to="/dashboard" className="category__breadcrumb-link">
    43→                {t('ui.backToDashboard', { defaultValue: '← Dashboard' })}
    44→              </Link>
    45→              <span className="category__breadcrumb-sep">/</span>
    46→              <span className="category__breadcrumb-icon">{category.icon}</span>
    47→              <span className="category__breadcrumb-name">{catName}</span>
    48→            </div>
    49→          </div>
    50→        </div>
    51→
    52→        <div className="category__layout">
    53→          {/* Sidebar */}
    54→          <motion.aside
    55→            className={`category__sidebar ${sidebarOpen ? '' : 'category__sidebar--closed'}`}
    56→            initial={{ x: -20, opacity: 0 }}
    57→            animate={{ x: 0, opacity: 1 }}
    58→            transition={{ duration: 0.4, ease: [0.22, 1, 0.36, 1] }}
    59→          >
    60→            <div className="category__sidebar-header">
    61→              <div className="category__sidebar-cat">
    62→                <div
    63→                  className="category__sidebar-icon"
    64→                  style={{ background: `${category.color}20`, borderColor: `${category.color}40` }}
    65→                >
    66→                  {category.icon}
    67→                </div>
    68→                <div>
    69→                  <h3 className="category__sidebar-name">{catName}</h3>
    70→                  <span className="category__sidebar-count">
    71→                    {category.tools.length} {t('ui.tools', { defaultValue: 'tools' })}
    72→                  </span>
    73→                </div>
    74→              </div>
    75→            </div>
    76→
    77→            {locked && (
    78→              <div className="category__sidebar-upgrade">
    79→                <span>🔒</span>
    80→                <div>
    81→                  <strong>{t('ui.proRequired', { defaultValue: 'Pro Required' })}</strong>
    82→                  <p>{t('ui.upgradeToUnlock', { defaultValue: 'Upgrade to unlock all tools' })}</p>
    83→                </div>
    84→                <Link to="/pricing" className="btn btn-primary btn-sm">
    85→                  {t('ui.upgrade', { defaultValue: 'Upgrade' })}
    86→                </Link>
    87→              </div>
    88→            )}
    89→
    90→            <nav className="category__sidebar-nav">
    91→              {category.tools.map((tool) => (
    92→                <button
    93→                  key={tool.id}
    94→                  className={`category__tool-btn ${selectedTool?.id === tool.id ? 'active' : ''}`}
    95→                  onClick={() => setSelectedTool(tool)}
    96→                >
    97→                  <span className="category__tool-btn-icon">{tool.icon}</span>
    98→                  <div className="category__tool-btn-text">
    99→                    <span className="category__tool-btn-name">
   100→                      {t(`tool.${tool.id}.name`, { defaultValue: tool.name })}
   101→                    </span>
   102→                    <span className="category__tool-btn-desc">
   103→                      {t(`tool.${tool.id}.desc`, { defaultValue: tool.description })}
   104→                    </span>
   105→                  </div>
   106→                  {selectedTool?.id === tool.id && (
   107→                    <motion.div
   108→                      className="category__tool-active-indicator"
   109→                      layoutId="activeToolIndicator"
   110→                    />
   111→                  )}
   112→                </button>
   113→              ))}
   114→            </nav>
   115→          </motion.aside>
   116→
   117→          {/* Main content */}
   118→          <main className="category__main">
   119→            <button
   120→              className="category__sidebar-toggle"
   121→              onClick={() => setSidebarOpen(!sidebarOpen)}
   122→              title={sidebarOpen ? 'Hide sidebar' : 'Show sidebar'}
   123→            >
   124→              {sidebarOpen ? '◀' : '▶'}
   125→            </button>
   126→
   127→            <AnimatePresence mode="wait">
   128→              {selectedTool && (
   129→                <motion.div
   130→                  key={selectedTool.id}
   131→                  className="category__content"
   132→                  initial={{ opacity: 0, x: 20 }}
   133→                  animate={{ opacity: 1, x: 0 }}
   134→                  exit={{ opacity: 0, x: -20 }}
   135→                  transition={{ duration: 0.3, ease: [0.22, 1, 0.36, 1] }}
   136→                >
   137→                  <AIToolInterface tool={selectedTool} categoryId={categoryId} />
   138→                </motion.div>
   139→              )}
   140→            </AnimatePresence>
   141→          </main>
   142→        </div>
   143→      </div>
   144→    </div>
   145→  );
   146→}
